// Pseudo-code: Agent registration and event bus
registerAgent('triage', TriageAgent)
registerAgent('investigation', InvestigationAgent)
eventBus.on('alert', (alert) => {
  agents.triage.handle(alert)
})

// Only call LLM when agent flags anomaly
if (agent.detectAnomaly(logEntry)) {
  llm.analyze(logEntry)
}

// Kafka consumer for alert topic
const consumer = kafka.consumer({ groupId: 'soc-agents' })
await consumer.subscribe({ topic: 'alerts' })
consumer.run({
  eachMessage: async ({ message }) => {
    processAlert(message.value)
  }
})
